import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.BYYsWsaA.js";const m=JSON.parse('{"title":"Bin Channels Design Spec","description":"","frontmatter":{},"headers":[],"relativePath":"specs/2026-03-15-bin-channels-design.md","filePath":"specs/2026-03-15-bin-channels-design.md"}'),s={name:"specs/2026-03-15-bin-channels-design.md"};function i(d,e,r,l,c,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="bin-channels-design-spec" tabindex="-1">Bin Channels Design Spec <a class="header-anchor" href="#bin-channels-design-spec" aria-label="Permalink to &quot;Bin Channels Design Spec&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Bin channels (<code>ChannelType = 2</code>) are forum-style channels with first-class code support. They combine Discord&#39;s forum functionality with pastebin capabilities — posts can be pure discussion (CTF writeups, questions), pure code, or a mix.</p><p>This feature also introduces three platform-wide capabilities:</p><ul><li><strong>Facebook-style nested replies</strong> on messages (one level deep)</li><li><strong>Edit history</strong> for messages (90-day retention)</li><li><strong>Syntax-highlighted source code attachments</strong> everywhere via Shiki</li></ul><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><h3 id="new-tables" tabindex="-1">New Tables <a class="header-anchor" href="#new-tables" aria-label="Permalink to &quot;New Tables&quot;">​</a></h3><h4 id="bin-posts" tabindex="-1"><code>bin_posts</code> <a class="header-anchor" href="#bin-posts" aria-label="Permalink to &quot;`bin_posts`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td>Uses <code>gen_bin_post_id()</code> (9-digit, created in migration following the <code>gen_server_id()</code> pattern)</td></tr><tr><td>channel_id</td><td>BIGINT FK → channels</td><td>The bin container channel</td></tr><tr><td>thread_channel_id</td><td>BIGINT FK → channels</td><td>Dedicated thread channel for general comments</td></tr><tr><td>author_id</td><td>BIGINT FK → users</td><td></td></tr><tr><td>title</td><td>VARCHAR(200)</td><td>Required</td></tr><tr><td>description</td><td>TEXT</td><td>Optional markdown body. Supports triple-backtick code blocks with language tags (e.g. ```python) rendered with Shiki, same as messages.</td></tr><tr><td>tags</td><td>TEXT[]</td><td>Postgres array, mix of admin-defined + freeform</td></tr><tr><td>created_at</td><td>TIMESTAMP</td><td></td></tr><tr><td>updated_at</td><td>TIMESTAMP</td><td></td></tr></tbody></table><h4 id="bin-post-files" tabindex="-1"><code>bin_post_files</code> <a class="header-anchor" href="#bin-post-files" aria-label="Permalink to &quot;`bin_post_files`&quot;">​</a></h4><p>Current version of files attached to a post.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>post_id</td><td>BIGINT FK → bin_posts</td><td></td></tr><tr><td>filename</td><td>VARCHAR(255)</td><td>e.g. <code>exploit.py</code>, <code>config.yaml</code></td></tr><tr><td>language</td><td>VARCHAR(50)</td><td>Shiki language ID, nullable for auto-detect</td></tr><tr><td>content</td><td>TEXT</td><td>The actual code</td></tr><tr><td>position</td><td>INT</td><td>Ordering within the post, UNIQUE(post_id, position)</td></tr></tbody></table><h4 id="bin-post-versions" tabindex="-1"><code>bin_post_versions</code> <a class="header-anchor" href="#bin-post-versions" aria-label="Permalink to &quot;`bin_post_versions`&quot;">​</a></h4><p>A version is created on post creation (version 1) and on each subsequent edit (version 2, 3, ...). The initial version snapshot is needed so that line comments always have a version to anchor to.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>post_id</td><td>BIGINT FK → bin_posts</td><td></td></tr><tr><td>version</td><td>INT</td><td>Sequential: 1 (initial), 2, 3...</td></tr><tr><td>description</td><td>TEXT</td><td>Description at time of snapshot</td></tr><tr><td>created_at</td><td>TIMESTAMP</td><td>When this version was saved</td></tr></tbody></table><h4 id="bin-post-version-files" tabindex="-1"><code>bin_post_version_files</code> <a class="header-anchor" href="#bin-post-version-files" aria-label="Permalink to &quot;`bin_post_version_files`&quot;">​</a></h4><p>File snapshots per version.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>version_id</td><td>BIGINT FK → bin_post_versions</td><td></td></tr><tr><td>filename</td><td>VARCHAR(255)</td><td></td></tr><tr><td>language</td><td>VARCHAR(50)</td><td></td></tr><tr><td>content</td><td>TEXT</td><td></td></tr><tr><td>position</td><td>INT</td><td></td></tr></tbody></table><h4 id="bin-line-comments" tabindex="-1"><code>bin_line_comments</code> <a class="header-anchor" href="#bin-line-comments" aria-label="Permalink to &quot;`bin_line_comments`&quot;">​</a></h4><p>Comments anchored to a specific line in a specific version/file.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>post_id</td><td>BIGINT FK → bin_posts</td><td></td></tr><tr><td>version_id</td><td>BIGINT FK → bin_post_versions</td><td></td></tr><tr><td>file_id</td><td>BIGINT FK → bin_post_version_files</td><td>Which file</td></tr><tr><td>line_number</td><td>INT</td><td></td></tr><tr><td>author_id</td><td>BIGINT FK → users</td><td></td></tr><tr><td>content</td><td>TEXT</td><td></td></tr><tr><td>parent_id</td><td>BIGINT FK → bin_line_comments (nullable)</td><td>Nested replies (one level)</td></tr><tr><td>created_at</td><td>TIMESTAMP</td><td></td></tr><tr><td>updated_at</td><td>TIMESTAMP</td><td></td></tr></tbody></table><h4 id="bin-channel-tags" tabindex="-1"><code>bin_channel_tags</code> <a class="header-anchor" href="#bin-channel-tags" aria-label="Permalink to &quot;`bin_channel_tags`&quot;">​</a></h4><p>Admin-defined tags per bin channel.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>channel_id</td><td>BIGINT FK → channels</td><td></td></tr><tr><td>name</td><td>VARCHAR(50)</td><td>UNIQUE(channel_id, name)</td></tr><tr><td>color</td><td>VARCHAR(7)</td><td>Hex color</td></tr></tbody></table><h3 id="modifications-to-existing-tables" tabindex="-1">Modifications to Existing Tables <a class="header-anchor" href="#modifications-to-existing-tables" aria-label="Permalink to &quot;Modifications to Existing Tables&quot;">​</a></h3><h4 id="messages-—-add-parent-id" tabindex="-1"><code>messages</code> — add <code>parent_id</code> <a class="header-anchor" href="#messages-—-add-parent-id" aria-label="Permalink to &quot;`messages` — add `parent_id`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>parent_id</td><td>BIGINT FK → messages (nullable)</td><td>NULL = top-level, set = reply</td></tr></tbody></table><p>Enables Facebook-style nested replies platform-wide. One level of nesting only — replies to replies are treated as replies to the parent.</p><h4 id="message-versions-—-new-table" tabindex="-1"><code>message_versions</code> — new table <a class="header-anchor" href="#message-versions-—-new-table" aria-label="Permalink to &quot;`message_versions` — new table&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>BIGSERIAL PK</td><td></td></tr><tr><td>message_id</td><td>BIGINT FK → messages</td><td></td></tr><tr><td>content</td><td>TEXT</td><td>Previous content</td></tr><tr><td>edited_at</td><td>TIMESTAMP</td><td>When this version was superseded</td></tr></tbody></table><p>Previous content is saved here before each edit. Versions older than 90 days are periodically purged.</p><h4 id="channels-—-no-schema-change-needed" tabindex="-1"><code>channels</code> — no schema change needed <a class="header-anchor" href="#channels-—-no-schema-change-needed" aria-label="Permalink to &quot;`channels` — no schema change needed&quot;">​</a></h4><p>The <code>channel_type</code> column already supports arbitrary integer values. Add <code>ChannelTypeBin = 2</code> constant to <code>internal/db/models.go</code> alongside the existing <code>ChannelTypeText</code> and <code>ChannelTypeVoice</code> constants.</p><h3 id="indexes" tabindex="-1">Indexes <a class="header-anchor" href="#indexes" aria-label="Permalink to &quot;Indexes&quot;">​</a></h3><p>Key indexes beyond PKs and FKs:</p><ul><li><code>bin_posts</code>: <code>(channel_id, created_at DESC)</code> — post listing</li><li><code>bin_post_files</code>: <code>(post_id, position)</code> — file ordering</li><li><code>bin_line_comments</code>: <code>(version_id, file_id, line_number)</code> — line comment queries</li><li><code>bin_channel_tags</code>: unique on <code>(channel_id, name)</code></li><li><code>message_versions</code>: <code>(message_id, edited_at)</code> — version history lookup</li><li><code>messages</code>: index on <code>parent_id WHERE parent_id IS NOT NULL</code> — reply tree queries</li></ul><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><h3 id="bin-post-crud" tabindex="-1">Bin Post CRUD <a class="header-anchor" href="#bin-post-crud" aria-label="Permalink to &quot;Bin Post CRUD&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST   /api/channels/{channelID}/posts          — Create a bin post</span></span>\n<span class="line"><span>GET    /api/channels/{channelID}/posts           — List posts (paginated, filterable)</span></span>\n<span class="line"><span>GET    /api/posts/{postID}                       — Get a single post with current files</span></span>\n<span class="line"><span>PUT    /api/posts/{postID}                       — Edit post (creates new version)</span></span>\n<span class="line"><span>DELETE /api/posts/{postID}                       — Delete post</span></span></code></pre></div><h3 id="post-versions" tabindex="-1">Post Versions <a class="header-anchor" href="#post-versions" aria-label="Permalink to &quot;Post Versions&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/posts/{postID}/versions              — List version history</span></span>\n<span class="line"><span>GET    /api/posts/{postID}/versions/{versionID}  — Get a specific version with its files</span></span></code></pre></div><h3 id="line-comments" tabindex="-1">Line Comments <a class="header-anchor" href="#line-comments" aria-label="Permalink to &quot;Line Comments&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/posts/{postID}/line-comments?version_id=X&amp;file_id=Y  — Get line comments for a file version</span></span>\n<span class="line"><span>POST   /api/posts/{postID}/line-comments         — Create line comment</span></span>\n<span class="line"><span>PUT    /api/line-comments/{id}                   — Edit line comment</span></span>\n<span class="line"><span>DELETE /api/line-comments/{id}                   — Delete line comment</span></span></code></pre></div><p>Line comment creation body: <code>{ version_id, file_id, line_number, content, parent_id? }</code></p><h3 id="general-comments" tabindex="-1">General Comments <a class="header-anchor" href="#general-comments" aria-label="Permalink to &quot;General Comments&quot;">​</a></h3><p>Each bin post gets a dedicated thread channel. General comments use the existing message endpoints unchanged:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/channels/{threadChannelID}/messages  — existing</span></span>\n<span class="line"><span>POST   /api/channels/{threadChannelID}/messages  — existing</span></span></code></pre></div><p>The <code>parent_id</code> field on messages enables nested replies within these threads.</p><h3 id="bin-channel-tags-1" tabindex="-1">Bin Channel Tags <a class="header-anchor" href="#bin-channel-tags-1" aria-label="Permalink to &quot;Bin Channel Tags&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/channels/{channelID}/tags            — List available tags</span></span>\n<span class="line"><span>POST   /api/channels/{channelID}/tags            — Create tag (manage_channels perm)</span></span>\n<span class="line"><span>DELETE /api/channels/{channelID}/tags/{tagID}    — Delete tag</span></span></code></pre></div><h3 id="platform-wide-addition" tabindex="-1">Platform-wide Addition <a class="header-anchor" href="#platform-wide-addition" aria-label="Permalink to &quot;Platform-wide Addition&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/messages/{id}/versions               — Get edit history for any message</span></span></code></pre></div><h3 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h3><p>All bin post endpoints validate that the target channel is <code>ChannelType = 2</code>. Requests against non-bin channels return <code>400 Bad Request</code> with <code>&quot;channel is not a bin channel&quot;</code>. Post mutations (edit, delete) check that the requesting user is the post author or has <code>manage_messages</code> permission. Tag CRUD requires <code>manage_channels</code> permission. All new tables use <code>ON DELETE CASCADE</code> on their foreign keys — deleting a post cascades to its files, versions, version files, line comments, and thread channel.</p><h3 id="post-listing-query-parameters" tabindex="-1">Post Listing Query Parameters <a class="header-anchor" href="#post-listing-query-parameters" aria-label="Permalink to &quot;Post Listing Query Parameters&quot;">​</a></h3><p><code>GET /api/channels/{channelID}/posts</code> supports:</p><ul><li><code>?tag=malware</code> — filter by tag</li><li><code>?language=python</code> — filter by language (any file in the post)</li><li><code>?author_id=123</code> — filter by author</li><li><code>?sort=newest|oldest|recently_active</code> — sort order</li><li><code>?limit=25&amp;offset=0</code> — pagination (max 50)</li></ul><h2 id="websocket-events" tabindex="-1">WebSocket Events <a class="header-anchor" href="#websocket-events" aria-label="Permalink to &quot;WebSocket Events&quot;">​</a></h2><h3 id="new-events" tabindex="-1">New Events <a class="header-anchor" href="#new-events" aria-label="Permalink to &quot;New Events&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Event</th><th>Payload</th><th>When</th></tr></thead><tbody><tr><td><code>BIN_POST_CREATE</code></td><td>Full post object with files</td><td>New post created</td></tr><tr><td><code>BIN_POST_UPDATE</code></td><td>Updated post + new version number</td><td>Post edited</td></tr><tr><td><code>BIN_POST_DELETE</code></td><td><code>{ post_id, channel_id }</code></td><td>Post deleted</td></tr><tr><td><code>BIN_LINE_COMMENT_CREATE</code></td><td>Line comment object</td><td>New line comment</td></tr><tr><td><code>BIN_LINE_COMMENT_UPDATE</code></td><td>Updated line comment</td><td>Line comment edited</td></tr><tr><td><code>BIN_LINE_COMMENT_DELETE</code></td><td><code>{ id, post_id }</code></td><td>Line comment deleted</td></tr></tbody></table><h3 id="events-that-work-for-free" tabindex="-1">Events That Work for Free <a class="header-anchor" href="#events-that-work-for-free" aria-label="Permalink to &quot;Events That Work for Free&quot;">​</a></h3><ul><li><code>MESSAGE_CREATE</code> / <code>MESSAGE_UPDATE</code> / <code>MESSAGE_DELETE</code> — general comments (they&#39;re messages in the thread channel)</li><li><code>REACTION_UPDATE</code> — reactions on comments</li><li><code>CHANNEL_CREATE</code> — when the thread channel is created for a new post</li></ul><h3 id="subscription-model" tabindex="-1">Subscription Model <a class="header-anchor" href="#subscription-model" aria-label="Permalink to &quot;Subscription Model&quot;">​</a></h3><p>Users subscribe to the bin channel ID to receive post-level events (<code>BIN_POST_CREATE/UPDATE/DELETE</code>). When viewing a specific post, they additionally subscribe to the post&#39;s thread channel for general comment events (<code>MESSAGE_CREATE</code> etc.). Line comment events are broadcast to all subscribers of the post&#39;s thread channel — since only users viewing that post are subscribed, this avoids noise. The existing <code>subscribe</code>/<code>unsubscribe</code> WebSocket messages are sufficient; no new subscription types needed.</p><h2 id="frontend-architecture" tabindex="-1">Frontend Architecture <a class="header-anchor" href="#frontend-architecture" aria-label="Permalink to &quot;Frontend Architecture&quot;">​</a></h2><h3 id="shared-components" tabindex="-1">Shared Components <a class="header-anchor" href="#shared-components" aria-label="Permalink to &quot;Shared Components&quot;">​</a></h3><h4 id="codeblock" tabindex="-1"><code>CodeBlock</code> <a class="header-anchor" href="#codeblock" aria-label="Permalink to &quot;`CodeBlock`&quot;">​</a></h4><p>Shiki-powered syntax-highlighted code display. Used in bin post view, message attachments with code file extensions, and inline markdown code blocks.</p><p>Props: <code>content</code>, <code>language</code>, <code>filename</code>, optional <code>onLineClick</code> for comment gutter.</p><p>Lazy-loads Shiki core (~15KB gzipped) and language grammars on demand.</p><h4 id="nestedreplies" tabindex="-1"><code>NestedReplies</code> <a class="header-anchor" href="#nestedreplies" aria-label="Permalink to &quot;`NestedReplies`&quot;">​</a></h4><p>Facebook-style reply rendering. Takes a flat list of messages, builds a tree from <code>parent_id</code>. One level of nesting only — replies to replies show as replies to the parent. Includes inline reply input.</p><p>Used in bin post general comments and available for future use in regular channels.</p><h3 id="bin-specific-components" tabindex="-1">Bin-Specific Components <a class="header-anchor" href="#bin-specific-components" aria-label="Permalink to &quot;Bin-Specific Components&quot;">​</a></h3><h4 id="binchannel" tabindex="-1"><code>BinChannel</code> <a class="header-anchor" href="#binchannel" aria-label="Permalink to &quot;`BinChannel`&quot;">​</a></h4><p>Replaces <code>ChatWindow</code> when <code>channel_type === 2</code>. Shows post list with title, author, tags, file count, comment count, timestamp. Includes filter bar (tag pills, language dropdown, sort selector) and &quot;New Post&quot; button.</p><h4 id="createpostmodal" tabindex="-1"><code>CreatePostModal</code> <a class="header-anchor" href="#createpostmodal" aria-label="Permalink to &quot;`CreatePostModal`&quot;">​</a></h4><p>Post creation form: title, description (markdown with Shiki-highlighted code blocks, optional), file editor (add multiple files with filename, language selector, code textarea), tag selector (admin tags as pills + freeform input), preview toggle.</p><h4 id="postview" tabindex="-1"><code>PostView</code> <a class="header-anchor" href="#postview" aria-label="Permalink to &quot;`PostView`&quot;">​</a></h4><p>Single post display with header (title, author, tags, version dropdown) and tabbed content:</p><ul><li><strong>Files tab</strong> — each file rendered with <code>CodeBlock</code>, tab bar for multiple files, line number gutter for clicking to add line comments</li><li><strong>Comments tab</strong> — general discussion using <code>NestedReplies</code> over the thread channel&#39;s messages</li><li><strong>Line Notes tab</strong> — grouped by file, line-anchored comments with &quot;Line 42&quot; badges, clicking jumps to the file and highlights the line</li></ul><h4 id="postlistitem" tabindex="-1"><code>PostListItem</code> <a class="header-anchor" href="#postlistitem" aria-label="Permalink to &quot;`PostListItem`&quot;">​</a></h4><p>Card in the bin channel list: title, tag pills, author avatar + name, file count, comment count, time ago, language indicators.</p><h3 id="changes-to-existing-components" tabindex="-1">Changes to Existing Components <a class="header-anchor" href="#changes-to-existing-components" aria-label="Permalink to &quot;Changes to Existing Components&quot;">​</a></h3><h4 id="channellist-tsx" tabindex="-1"><code>ChannelList.tsx</code> <a class="header-anchor" href="#channellist-tsx" aria-label="Permalink to &quot;`ChannelList.tsx`&quot;">​</a></h4><p>Add bin channel section with <code>&lt;/&gt;</code> icon. Filter: <code>channels.filter(ch =&gt; ch.type === 2)</code>.</p><h4 id="createchannelmodal-tsx" tabindex="-1"><code>CreateChannelModal.tsx</code> <a class="header-anchor" href="#createchannelmodal-tsx" aria-label="Permalink to &quot;`CreateChannelModal.tsx`&quot;">​</a></h4><p>Add third radio option: &quot;Bin&quot; with description &quot;Code sharing &amp; discussion&quot;.</p><h4 id="message-tsx" tabindex="-1"><code>Message.tsx</code> <a class="header-anchor" href="#message-tsx" aria-label="Permalink to &quot;`Message.tsx`&quot;">​</a></h4><ul><li>Render <code>parent_id</code> replies inline (&quot;replying to @user&quot; link above message)</li><li>&quot;(edited)&quot; click handler opens version history popover</li></ul><h4 id="messageinput-tsx" tabindex="-1"><code>MessageInput.tsx</code> <a class="header-anchor" href="#messageinput-tsx" aria-label="Permalink to &quot;`MessageInput.tsx`&quot;">​</a></h4><p>Add <code>parent_id</code> support. When replying, show reply bar above input (partial infrastructure already exists via <code>replyTo</code> prop).</p><h4 id="attachment-rendering-platform-wide" tabindex="-1">Attachment Rendering (platform-wide) <a class="header-anchor" href="#attachment-rendering-platform-wide" aria-label="Permalink to &quot;Attachment Rendering (platform-wide)&quot;">​</a></h4><p>When a message attachment has a known code extension (<code>.py</code>, <code>.go</code>, <code>.js</code>, <code>.sh</code>, <code>.yaml</code>, <code>.rs</code>, <code>.c</code>, <code>.toml</code>, <code>.ps1</code>, <code>.lua</code>, <code>.rb</code>, <code>.java</code>, <code>.asm</code>, etc.), render with <code>CodeBlock</code> instead of a generic download link. Fetch file content and display with syntax highlighting. Files over 100KB fall back to download with a &quot;Preview&quot; button.</p><h2 id="syntax-highlighting" tabindex="-1">Syntax Highlighting <a class="header-anchor" href="#syntax-highlighting" aria-label="Permalink to &quot;Syntax Highlighting&quot;">​</a></h2><h3 id="shiki-configuration" tabindex="-1">Shiki Configuration <a class="header-anchor" href="#shiki-configuration" aria-label="Permalink to &quot;Shiki Configuration&quot;">​</a></h3><p>Singleton highlighter instance at <code>frontend/src/lib/shiki.ts</code>. Lazy-loads language grammars on demand — only languages visible on screen are fetched.</p><h3 id="custom-theme" tabindex="-1">Custom Theme <a class="header-anchor" href="#custom-theme" aria-label="Permalink to &quot;Custom Theme&quot;">​</a></h3><p>Matches the Parley green terminal aesthetic:</p><table tabindex="0"><thead><tr><th>Token</th><th>Color</th></tr></thead><tbody><tr><td>Background</td><td><code>#0a0a0a</code></td></tr><tr><td>Default text</td><td><code>#e0e0e0</code></td></tr><tr><td>Keywords</td><td><code>#32CD32</code> (lime green)</td></tr><tr><td>Strings</td><td><code>#228B22</code> (dark green)</td></tr><tr><td>Comments</td><td><code>#555555</code></td></tr><tr><td>Numbers/constants</td><td><code>#66ff66</code></td></tr><tr><td>Types</td><td><code>#44aa44</code></td></tr><tr><td>Functions</td><td><code>#ffffff</code></td></tr></tbody></table><h3 id="extension-→-language-mapping" tabindex="-1">Extension → Language Mapping <a class="header-anchor" href="#extension-→-language-mapping" aria-label="Permalink to &quot;Extension → Language Mapping&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.py → python       .go → go            .rs → rust</span></span>\n<span class="line"><span>.js → javascript   .ts → typescript    .sh/.bash → bash</span></span>\n<span class="line"><span>.ps1 → powershell  .lua → lua          .c/.h → c</span></span>\n<span class="line"><span>.yaml/.yml → yaml  .json → json        .toml → toml</span></span>\n<span class="line"><span>.rb → ruby         .java → java        .asm/.s → asm</span></span></code></pre></div><h3 id="render-locations" tabindex="-1">Render Locations <a class="header-anchor" href="#render-locations" aria-label="Permalink to &quot;Render Locations&quot;">​</a></h3><ol><li><strong>Bin post files</strong> — full <code>CodeBlock</code> with line numbers and comment gutter</li><li><strong>Message attachments</strong> — <code>CodeBlock</code> in collapsible container (filename header, click to expand/collapse)</li><li><strong>Inline markdown code blocks</strong> — triple-backtick blocks get Shiki highlighting</li></ol><h2 id="edit-history" tabindex="-1">Edit History <a class="header-anchor" href="#edit-history" aria-label="Permalink to &quot;Edit History&quot;">​</a></h2><h3 id="message-edit-history-platform-wide" tabindex="-1">Message Edit History (Platform-wide) <a class="header-anchor" href="#message-edit-history-platform-wide" aria-label="Permalink to &quot;Message Edit History (Platform-wide)&quot;">​</a></h3><p>When a message is edited, the previous content is saved to <code>message_versions</code> before the update. The <code>messages</code> table always holds the latest version.</p><p>Frontend: &quot;(edited)&quot; indicator (already displayed) gets a click handler opening a popover with version list and timestamps. Clicking a version shows the previous content.</p><h3 id="bin-post-edit-history" tabindex="-1">Bin Post Edit History <a class="header-anchor" href="#bin-post-edit-history" aria-label="Permalink to &quot;Bin Post Edit History&quot;">​</a></h3><p>When a post is edited:</p><ol><li>Current files are snapshot into <code>bin_post_version_files</code> linked to a new <code>bin_post_versions</code> row</li><li>Current description is saved on the version row</li><li><code>bin_post_files</code> rows are updated with the new content</li><li><code>bin_posts.updated_at</code> is set</li></ol><p>Frontend: Version dropdown in post header (&quot;v3 · edited 2h ago&quot;). Selecting a previous version shows that snapshot read-only with a banner. Line comments are filtered to the selected version.</p><h3 id="retention" tabindex="-1">Retention <a class="header-anchor" href="#retention" aria-label="Permalink to &quot;Retention&quot;">​</a></h3><p>Versions older than 90 days are purged. Applies to both <code>message_versions</code> and <code>bin_post_versions</code> / <code>bin_post_version_files</code>. Line comments anchored to purged versions are purged along with them (cascading delete on <code>version_id</code> FK). Cleanup runs as a goroutine on app startup that executes the purge query once, then on a 24-hour ticker thereafter.</p><h2 id="implementation-scope-note" tabindex="-1">Implementation Scope Note <a class="header-anchor" href="#implementation-scope-note" aria-label="Permalink to &quot;Implementation Scope Note&quot;">​</a></h2><p>While this spec covers three capabilities (bin channels, nested replies, edit history), they are delivered together because bin channels depend on both nested replies and edit history. The implementation plan should order them so that platform-wide features (nested replies, edit history, syntax highlighting) land first, then bin-specific work builds on top.</p><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>DM edit history (same pattern, separate effort)</li><li>Custom Shiki grammars for YARA/Sigma rules (future)</li><li>Voting/scoring on posts</li><li>Post access control beyond channel permissions</li></ul>',118)])])}const u=t(s,[["render",i]]);export{m as __pageData,u as default};
